import{_ as e,o as a,c as t,a2 as s}from"./chunks/framework.DeNJmwJc.js";const c=JSON.parse('{"title":"Chapter 4 — Vim vs Vi vs Neovim","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/04-vim-vs-vi-vs-neovim.md","filePath":"chapters/04-vim-vs-vi-vs-neovim.md"}'),r={name:"chapters/04-vim-vs-vi-vs-neovim.md"};function o(n,i,l,d,h,p){return a(),t("div",null,[...i[0]||(i[0]=[s(`<h1 id="chapter-4-—-vim-vs-vi-vs-neovim" tabindex="-1">Chapter 4 — Vim vs Vi vs Neovim <a class="header-anchor" href="#chapter-4-—-vim-vs-vi-vs-neovim" aria-label="Permalink to &quot;Chapter 4 — Vim vs Vi vs Neovim&quot;">​</a></h1><blockquote><p><em>&quot;Three editors, one philosophy—but vastly different capabilities.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐ Beginner <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>If you search online for &quot;learn Vim,&quot; you&#39;ll quickly encounter three names:</p><ul><li><strong>Vi</strong></li><li><strong>Vim</strong></li><li><strong>Neovim</strong></li></ul><p>This is confusing for beginners.</p><p>Which one should you install?</p><p>Which one should you learn?</p><p>Do they even work the same way?</p><p>This chapter answers those questions clearly.</p><hr><h1 id="the-family-tree" tabindex="-1">The Family Tree <a class="header-anchor" href="#the-family-tree" aria-label="Permalink to &quot;The Family Tree&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1976 — EX (Bill Joy)</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>1979 — Vi (Bill Joy)</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>1991 — Vim (Bram Moolenaar)</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>2014 — Neovim (Community Fork)</span></span></code></pre></div><p>Each version added features while preserving the core editing model.</p><hr><h1 id="vi-—-the-original-1979" tabindex="-1">Vi — The Original (1979) <a class="header-anchor" href="#vi-—-the-original-1979" aria-label="Permalink to &quot;Vi — The Original (1979)&quot;">​</a></h1><h2 id="what-is-vi" tabindex="-1">What Is Vi? <a class="header-anchor" href="#what-is-vi" aria-label="Permalink to &quot;What Is Vi?&quot;">​</a></h2><p><strong>Vi</strong> stands for <strong>Visual</strong> (originally the visual mode of the <code>ex</code> editor).</p><p>It was written by <strong>Bill Joy</strong> in 1979 and shipped with every Unix system.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li>Modal editing (Normal, Insert, Command modes)</li><li>Basic navigation (<code>h</code>, <code>j</code>, <code>k</code>, <code>l</code>)</li><li>Simple editing commands</li><li>Extremely lightweight</li><li>Portable to nearly any system</li></ul><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>No syntax highlighting</li><li>No multiple undo (only one level)</li><li>No split windows</li><li>No plugins</li><li>No scripting</li><li>No arrow keys in insert mode</li></ul><h2 id="where-vi-is-still-used" tabindex="-1">Where Vi Is Still Used <a class="header-anchor" href="#where-vi-is-still-used" aria-label="Permalink to &quot;Where Vi Is Still Used&quot;">​</a></h2><ul><li>Embedded systems</li><li>Minimal Docker containers</li><li>Recovery environments</li><li>Old Unix certification exams</li></ul><hr><h1 id="vim-—-the-improvement-1991" tabindex="-1">Vim — The Improvement (1991) <a class="header-anchor" href="#vim-—-the-improvement-1991" aria-label="Permalink to &quot;Vim — The Improvement (1991)&quot;">​</a></h1><h2 id="what-is-vim" tabindex="-1">What Is Vim? <a class="header-anchor" href="#what-is-vim" aria-label="Permalink to &quot;What Is Vim?&quot;">​</a></h2><p><strong>Vim</strong> stands for <strong>Vi Improved</strong>.</p><p>Created by <strong>Bram Moolenaar</strong>, it started as a port of Vi to the Amiga but grew into a full rewrite.</p><h2 id="what-vim-added-over-vi" tabindex="-1">What Vim Added Over Vi <a class="header-anchor" href="#what-vim-added-over-vi" aria-label="Permalink to &quot;What Vim Added Over Vi&quot;">​</a></h2><h3 id="usability" tabindex="-1">Usability <a class="header-anchor" href="#usability" aria-label="Permalink to &quot;Usability&quot;">​</a></h3><ul><li>Arrow keys in insert mode</li><li>Mouse support</li><li>Multiple undo / redo</li><li>Visual mode (selecting text visually)</li><li>On-screen help (<code>:help</code>)</li></ul><h3 id="visual-features" tabindex="-1">Visual Features <a class="header-anchor" href="#visual-features" aria-label="Permalink to &quot;Visual Features&quot;">​</a></h3><ul><li>Syntax highlighting</li><li>Color schemes</li><li>Split windows</li><li>Tab pages</li></ul><h3 id="extensibility" tabindex="-1">Extensibility <a class="header-anchor" href="#extensibility" aria-label="Permalink to &quot;Extensibility&quot;">​</a></h3><ul><li>Vimscript scripting language</li><li>Plugin system</li><li>Package management</li><li>User-defined functions</li></ul><h3 id="productivity" tabindex="-1">Productivity <a class="header-anchor" href="#productivity" aria-label="Permalink to &quot;Productivity&quot;">​</a></h3><ul><li>Registers (multiple clipboards)</li><li>Macros (record and replay actions)</li><li>Jump list</li><li>Change list</li><li>Quickfix list</li></ul><h2 id="why-most-people-mean-vim" tabindex="-1">Why Most People Mean Vim <a class="header-anchor" href="#why-most-people-mean-vim" aria-label="Permalink to &quot;Why Most People Mean Vim&quot;">​</a></h2><p>When someone says &quot;I use Vim,&quot; they almost always mean <strong>Vim</strong>, not the original Vi.</p><hr><h1 id="neovim-—-the-modern-fork-2014" tabindex="-1">Neovim — The Modern Fork (2014) <a class="header-anchor" href="#neovim-—-the-modern-fork-2014" aria-label="Permalink to &quot;Neovim — The Modern Fork (2014)&quot;">​</a></h1><h2 id="what-is-neovim" tabindex="-1">What Is Neovim? <a class="header-anchor" href="#what-is-neovim" aria-label="Permalink to &quot;What Is Neovim?&quot;">​</a></h2><p><strong>Neovim</strong> is a <strong>fork</strong> of Vim created by a community of developers who wanted to modernize Vim&#39;s codebase.</p><p>It is <strong>not</strong> a separate editor—it&#39;s a refactored, improved Vim.</p><h2 id="what-neovim-improved-over-vim" tabindex="-1">What Neovim Improved Over Vim <a class="header-anchor" href="#what-neovim-improved-over-vim" aria-label="Permalink to &quot;What Neovim Improved Over Vim&quot;">​</a></h2><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><ul><li>Better code structure</li><li>Asynchronous job control</li><li>Built-in terminal emulator</li><li>Remote plugin architecture</li></ul><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><ul><li><strong>Lua</strong> as a first-class configuration language (faster, cleaner than Vimscript)</li><li>Better API for plugin developers</li></ul><h3 id="language-support" tabindex="-1">Language Support <a class="header-anchor" href="#language-support" aria-label="Permalink to &quot;Language Support&quot;">​</a></h3><ul><li>Built-in LSP (Language Server Protocol) client</li><li>Treesitter for smarter syntax highlighting</li><li>Better integration with modern developer tools</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Faster startup time</li><li>Lower memory usage</li><li>Better handling of large files</li></ul><hr><h1 id="feature-comparison-table" tabindex="-1">Feature Comparison Table <a class="header-anchor" href="#feature-comparison-table" aria-label="Permalink to &quot;Feature Comparison Table&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Feature</th><th>Vi</th><th>Vim</th><th>Neovim</th></tr></thead><tbody><tr><td>Modal editing</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Syntax highlighting</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Multiple undo</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Visual mode</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Split windows</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Plugins</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Vimscript</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Lua config</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Built-in terminal</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>LSP client</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Treesitter</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Async plugins</td><td>❌</td><td>(partial)</td><td>✅</td></tr><tr><td>Mouse support</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Package manager</td><td>❌</td><td>✅ (8.0+)</td><td>✅ (native)</td></tr></tbody></table><hr><h1 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h1><p>Here&#39;s the important part:</p><blockquote><p><strong>Nearly everything you learn in Vim works identically in Neovim.</strong></p></blockquote><p>The core editing model is the same:</p><ul><li><code>i</code> enters insert mode</li><li><code>Esc</code> returns to normal mode</li><li><code>dd</code> deletes a line</li><li><code>:wq</code> saves and quits</li><li>All motions, operators, and text objects</li></ul><p>If you learn commands in Vim, you can use them in Neovim, and vice versa.</p><hr><h1 id="configuration-differences" tabindex="-1">Configuration Differences <a class="header-anchor" href="#configuration-differences" aria-label="Permalink to &quot;Configuration Differences&quot;">​</a></h1><h2 id="vim-uses-vimrc" tabindex="-1">Vim uses <code>.vimrc</code> <a class="header-anchor" href="#vim-uses-vimrc" aria-label="Permalink to &quot;Vim uses \`.vimrc\`&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.vimrc</span></span></code></pre></div><p>Written in <strong>Vimscript</strong>:</p><div class="language-vim vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vim</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> tabstop</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">colorscheme</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> desert</span></span></code></pre></div><h2 id="neovim-uses-init-lua-or-init-vim" tabindex="-1">Neovim uses <code>init.lua</code> (or <code>init.vim</code>) <a class="header-anchor" href="#neovim-uses-init-lua-or-init-vim" aria-label="Permalink to &quot;Neovim uses \`init.lua\` (or \`init.vim\`)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/nvim/init.lua</span></span></code></pre></div><p>Written in <strong>Lua</strong>:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vim.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">number</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vim.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tabstop</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vim.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">colorscheme</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;desert&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Neovim also supports the old <code>.vimrc</code> syntax, so you can start with what you know.</p><hr><h1 id="which-one-should-you-learn" tabindex="-1">Which One Should You Learn? <a class="header-anchor" href="#which-one-should-you-learn" aria-label="Permalink to &quot;Which One Should You Learn?&quot;">​</a></h1><h2 id="if-you-re-a-beginner-start-with-neovim" tabindex="-1">If you&#39;re a beginner: Start with Neovim <a class="header-anchor" href="#if-you-re-a-beginner-start-with-neovim" aria-label="Permalink to &quot;If you&#39;re a beginner: Start with Neovim&quot;">​</a></h2><p>Reasons:</p><ul><li>Modern features out of the box</li><li>Larger plugin ecosystem</li><li>Better documentation for new users</li><li>Lua is easier to learn than Vimscript</li><li>Active community development</li></ul><h2 id="if-you-need-vim-on-servers" tabindex="-1">If you need Vim on servers <a class="header-anchor" href="#if-you-need-vim-on-servers" aria-label="Permalink to &quot;If you need Vim on servers&quot;">​</a></h2><p>Learn basic Vim commands anyway.</p><p>Most servers have <code>vim</code> or <code>vi</code> installed. The core commands are identical.</p><hr><h1 id="graphical-variants" tabindex="-1">Graphical Variants <a class="header-anchor" href="#graphical-variants" aria-label="Permalink to &quot;Graphical Variants&quot;">​</a></h1><p>Both Vim and Neovim have graphical versions:</p><table tabindex="0"><thead><tr><th>Name</th><th>Based On</th><th>Description</th></tr></thead><tbody><tr><td>GVim</td><td>Vim</td><td>Standalone GUI version of Vim</td></tr><tr><td>MacVim</td><td>Vim</td><td>macOS-native Vim GUI</td></tr><tr><td>Neovide</td><td>Neovim</td><td>Rust-based Neovim GUI</td></tr><tr><td>Goneovim</td><td>Neovim</td><td>Go-based Neovim GUI</td></tr></tbody></table><p>These provide:</p><ul><li>Native menus and toolbars</li><li>Better font rendering</li><li>Scrollbar support</li><li>System clipboard integration</li></ul><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><strong>Vi</strong> (1979) is the original—minimal but limited.</li><li><strong>Vim</strong> (1991) added plugins, syntax highlighting, and usability.</li><li><strong>Neovim</strong> (2014) modernized the architecture with Lua, LSP, and async support.</li><li>Core editing commands are identical across all three.</li><li><strong>Neovim is recommended for new users</strong>, while learning Vim commands prepares you for server environments.</li></ul><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Vi, Vim, and Neovim share the same editing philosophy.</li><li>Each version builds upon the previous one.</li><li>The commands you learn transfer across all three.</li><li>Neovim is the most modern and actively developed version.</li><li>You can use Vim keybindings even in GUI editors like VS Code.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Research whether Vi is installed on your system.</li><li>Identify which version you have installed (Vi or Vim).</li><li>Open Vim and try <code>:version</code> to see your version details.</li><li>Check if Neovim is available for your operating system.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><strong><a href="./05-installing-vim.html">Chapter 5 — Installing Vim &amp; Neovim</a></strong></p><p>We&#39;ll walk through installing Vim and Neovim on Linux, Windows, and macOS, with detailed steps for each operating system.</p>`,106)])])}const u=e(r,[["render",o]]);export{c as __pageData,u as default};
